update crm_contract
contract_no = #{contractNo}, contract_name = #{contractName}, customer_id = #{customerId}, order_id = #{orderId}, amount = #{amount}, sign_date = #{signDate}, start_date = #{startDate}, end_date = #{endDate}, status = #{status}, attachment = #{attachment}, belong_user_id = #{belongUserId}, belong_dept_id = #{belongDeptId}, update_by = #{updateBy}, remark = #{remark}, update_time = sysdate()
where contract_id = #{contractId}

update crm_contract
set belong_user_id = #{belongUserId}, belong_dept_id = #{belongDeptId}
where customer_id = #{customerId}

mapper.select:
SELECT c.status AS name, COUNT(1) AS value FROM crm_contract c WHERE c.del_flag = '0'
${params.dataScope}
GROUP BY c.status

SELECT DATE_FORMAT(c.create_time, '%Y-%m') AS month, SUM(c.amount) AS total FROM crm_contract c WHERE c.del_flag = '0' AND c.create_time >= DATE_FORMAT(DATE_SUB(NOW(), INTERVAL 5 MONTH), '%Y-%m-01')
${params.dataScope}
GROUP BY month ORDER BY month
